                Object.keys(tableEdit[child[tableIndex]]).forEach(edit => {
                    if (child.hasOwnProperty(edit)) {
                        child[edit]=tableEdit[child[tableIndex]][edit];
//                        node.warn(["mergeChild edit ",edit,child[edit]])
                    }
                });
            }
            if (child.hasOwnProperty("_children")) {
                mergeChildEdits(child._children);
            }
        })
    }


    Object.keys(destination).forEach(row => {
        if (destination[row].hasOwnProperty(tableIndex)) {
            if (tableEdit.hasOwnProperty(row)) {
                Object.keys(tableEdit[row]).forEach(edit => {
                    destination[row][edit]=tableEdit[row][edit];
                });
            }
            if (destination[row].hasOwnProperty("_children")) {
                mergeChildEdits(destination[row]._children);
            }
       }
    });
}

// deep search for a column including nested columns
var searchTabulatorColumn = function (columns,key,match) {
    var result;
    for (let column of columns) {
        if (column.hasOwnProperty("columns")) {
            result = searchTabulatorColumn(column.columns,key,match);
            if (result!==undefined) return result;
        } else if (column.hasOwnProperty(key) && column[key]===match) {
            return column;
        }
    }
};

// command message to update add or update data on ui-table
var msgToTable={};
