// Code added here will be run once
// whenever the node is started.

// Parse HSL values

function parseHSL(hslString) {
    const [h, s, l] = hslString.split(',').map(Number);

    // Validate HSL values
    if (isNaN(h) || isNaN(s) || isNaN(l)) {
        throw new Error("Invalid HSL format: values must be numbers");
    }

    if (h < 0 || h > 720) {
        throw new Error("Hue (h) must be between 0 and 720");
    }

    if (s < 0 || s > 100) {
        throw new Error("Saturation (s) must be between 0 and 100");
    }

    if (l < 0 || l > 100) {
        throw new Error("Lightness (l) must be between 0 and 100");
    }

    return { h, s, l };
};
this.parseHSL2 = parseHSL;

// Parse fixtures string to expand list of numbers

function expandFixtures( fixturesStr) {
    const terms = fixturesStr.split('+');
    const result = [];

    for (const term of terms) {
        if (term.includes('>')) {
            const [start, end] = term.split('>').map(Number);

            if (isNaN(start) || isNaN(end)) {
                throw new Error(`Invalid range in fixtures: ${term}`);
            }

            for (let i = start; i <= end; i++) {
                result.push(i);
            }
        } else {
            const num = Number(term);

            if (isNaN(num)) {
                throw new Error(`Invalid number in fixtures: ${term}`);
            }

            result.push(num);
        }
     }
    return result;
};
this.expandFixtures2 = expandFixtures;


/**
 * Generates a rainbow structure based on HSL color ranges and fixtures
 * @param {string} hsl1 - Starting HSL values as "h,s,l" where h=0-720, s=0-100, l=0-100
 * @param {string} hsl2 - Ending HSL values as "h,s,l" where h=0-720, s=0-100, l=0-100
 * @param {string} fixtures - String representing list of numbers (e.g. "1>3+5+7>9")
 * @returns {Array} Array of objects with ch, lvl, and hs properties
 */
function rainbow(hsl1, hsl2, fixtures) {
    try {
        // Parse inputs
        const hsl1Values = parseHSL(hsl1);
        const hsl2Values = parseHSL(hsl2);
        const expandedFixtures = expandFixtures(fixtures);

        const N = expandedFixtures.length-1;

        if (N === 0) {
            return [];
        }

        // Calculate ranges
        const range_h = hsl2Values.h - hsl1Values.h;
        const range_s = hsl2Values.s - hsl1Values.s;
        const range_l = hsl2Values.l - hsl1Values.l;

        // Generate result structure
        return expandedFixtures.map((ch, index) => {
            // Calculate position-based values
            let h = Math.round(hsl1Values.h + (range_h / N) * index);
            if (h > 360) h = h % 360;

            const s = Math.round(hsl1Values.s + (range_s / N) * index);
            const l = Math.round(hsl1Values.l + (range_l / N) * index);

            return {
                ch,
                lvl: l,
                hs: [h, s]
            };
        });
    } catch (error) {
        console.error("Error in rainbow function:", error.message);
        throw error;
    }
}

this.rainbow2 = rainbow;

