let buffer = context.get('buffer') || '';
buffer += msg.payload;

// Split by double newlines to find complete blocks
const blocks = [];
const parts = buffer.split(/\n\n|\r\n\r\n/);

// All parts except the last are complete blocks
for (let i = 0; i < parts.length - 1; i++) {
    const block = parts[i].trim();
    if (block.length > 0) {
        blocks.push(block);
    }
}

// Keep the last part as it might be incomplete
context.set('buffer', parts[parts.length - 1]);

// Process each complete block
if (blocks.length > 0) {
    return [blocks.map(block => ({payload: block}))];
}

return null;

const block = msg.payload;
const lines = block.split(/\r?\n/);

if (lines.length === 0) return null;

const headerLine = lines[0];
const match = headerLine.match(/^([A-Z\s]+):/);

if (!match) {
    // Check for ACK/NAK responses
    if (headerLine === 'ACK' || headerLine === 'NAK') {
        msg.payload = {
            blockType: headerLine,
            data: {}
        };
        return msg;
    }
    return null;
}

const blockType = match[1].trim();
const data = {};

