for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (line === '') continue;

    // Most blocks have format: "index value" or "key: value"
    if (line.includes(':')) {
        // Key-value format (like PROTOCOL PREAMBLE, VIDEOHUB DEVICE)
        const colonIdx = line.indexOf(':');
        const key = line.substring(0, colonIdx).trim();
        const value = line.substring(colonIdx + 1).trim();
        data[key] = value;
    } else {
        // Index-value format (most routing/label blocks)
        const spaceIdx = line.indexOf(' ');
        if (spaceIdx > 0) {
            const index = line.substring(0, spaceIdx);
            const value = line.substring(spaceIdx + 1);
            data[index] = value;
        }
    }
}

msg.payload = {
    blockType: blockType,
    data: data
};

return msg;

