function pad4(buf) {
    const pad = (4 - (buf.length % 4)) % 4;
    return pad ? Buffer.concat([buf, Buffer.alloc(pad)]) : buf;
}

const address = '/KLANGfabrik/control/RequestListOfPresets';
const addressBuf = pad4(Buffer.from(address + '\0', 'utf8'));
const typeTagBuf = pad4(Buffer.from(',\0', 'utf8'));

msg.payload = Buffer.concat([addressBuf, typeTagBuf]);
msg.ip = '192.168.200.146';
msg.port = 9110;
return msg;

const buf = msg.payload;
msg.payload = {
    length: buf.length,
    hex: buf.toString('hex').match(/.{1,2}/g)?.join(' ') || '',
    text: buf.toString('utf8').replace(/\u0000/g, '\\0')
};
return msg;

// Initialise an in-progress results array and store the targets for the
// collector to match against.
var targets = msg.targets;
var pending = targets.map(function(t) {
    return { asset_tag: t.asset_tag, nic: t.nic, ip: t.ip,
             packets_sent: 3, packets_received: null,
             avg_ms: null, loss_pct: null, status: 'unknown' };
});
flow.set('network_ping_pending', JSON.parse(JSON.stringify(pending)));
flow.set('network_ping_count', 0);
flow.set('network_ping_total', targets.length);
// Fan out one message per target
var msgs = targets.map(function(t) {
    return { payload: t };
});
return [msgs];

// msg.payload  = stdout from ping
// msg._msgid    = used to correlate back to original target (Node-RED preserves _msgid on split)
// We stored the target in msg.payload before exec replaced it; exec puts stdout in msg.payload.
// The original target ip is recoverable from the ping output first line.
var stdout = (typeof msg.payload === 'string') ? msg.payload : '';
var stderr = (typeof msg.payload2 === 'string') ? msg.payload2 : '';
var combined = stdout + stderr;

// Extract IP from "PING x.x.x.x" line
var ipMatch = combined.match(/PING\s+[^\s]*\s+\(([^)]+)\)/) ||
              combined.match(/PING\s+([\d.]+)/);
var ip = ipMatch ? ipMatch[1] : null;

var result = {
    ip: ip,
    packets_sent: 3,
    packets_received: 0,
    avg_ms: null,
    loss_pct: 100,
    status: 'down'
};

// Parse "3 packets transmitted, 3 packets received, 0.0% packet loss"
var statsMatch = combined.match(/(\d+) packets transmitted,\s*(\d+) (?:packets )?received,\s*([\d.]+)% packet loss/);
if (statsMatch) {
    result.packets_sent = parseInt(statsMatch[1]);
    result.packets_received = parseInt(statsMatch[2]);
    result.loss_pct = parseFloat(statsMatch[3]);
}

// Parse "round-trip min/avg/max/stddev = 1.234/2.345/3.456/0.567 ms"
var rttMatch = combined.match(/min\/avg\/max.*?=\s*[\d.]+\/([\d.]+)\//);
if (rttMatch) {
    result.avg_ms = parseFloat(rttMatch[1]);
}

if (result.loss_pct === 0 && result.avg_ms !== null) {
    result.status = result.avg_ms > 50 ? 'high_latency' : 'ok';
} else if (result.loss_pct > 0 && result.packets_received > 0) {
    result.status = 'down'; // partial loss still counts as down
} else {
    result.status = 'down';
}

msg.pingResult = result;
return msg;

var result = msg.pingResult;
var pending = flow.get('network_ping_pending') || [];
var count = (flow.get('network_ping_count') || 0) + 1;
var total = flow.get('network_ping_total') || pending.length;

// Match by IP
var idx = pending.findIndex(function(r) { return r.ip === result.ip; });
if (idx >= 0) {
    pending[idx].packets_sent     = result.packets_sent;
    pending[idx].packets_received = result.packets_received;
    pending[idx].avg_ms           = result.avg_ms;
    pending[idx].loss_pct         = result.loss_pct;
    pending[idx].status           = result.status;
}

flow.set('network_ping_pending', pending);
flow.set('network_ping_count', count);

// When all results are in, commit to the stable cache
if (count >= total) {
    flow.set('network_ping_results', JSON.parse(JSON.stringify(pending)));
    flow.set('network_ping_generated_at', new Date().toISOString());
    flow.set('network_ping_count', 0);
}

