const TRACKED  = ['name', 'mute', 'visible', 'solo'];
const SEVERITY = { name: 'warning', mute: 'critical', visible: 'warning', solo: 'warning' };

// Accumulate votes[ch][attr][jsonVal] = { count, mixes[] }
const votes = {};
for (const key of stateKeys) {
    const [mixStr, chStr] = key.split(':');
    const mix = parseInt(mixStr);
    const ch  = parseInt(chStr);
    const e   = state[key];
    if (!votes[ch]) votes[ch] = {};
    for (const attr of TRACKED) {
        if (e[attr] === undefined) continue;
        const v = JSON.stringify(e[attr]);
        if (!votes[ch][attr]) votes[ch][attr] = {};
        if (!votes[ch][attr][v]) votes[ch][attr][v] = { count: 0, mixes: [] };
        votes[ch][attr][v].count++;
        votes[ch][attr][v].mixes.push(mix);
    }
}

// Resolve consensus: plurality, tie-break by lowest mix number
const channels = {};
for (const ch of Object.keys(votes)) {
    channels[ch] = {};
    for (const attr of TRACKED) {
        if (!votes[ch][attr]) continue;
        const candidates = Object.entries(votes[ch][attr]);
        candidates.sort((a, b) =>
            b[1].count !== a[1].count
                ? b[1].count - a[1].count
                : Math.min(...a[1].mixes) - Math.min(...b[1].mixes)
        );
        const [topVal, topInfo] = candidates[0];
        const total = candidates.reduce((s, [, v]) => s + v.count, 0);
        channels[ch][attr] = {
            consensus:   JSON.parse(topVal),
            vote_count:  topInfo.count,
            total_votes: total
        };
    }
}

const generatedAt = new Date().toISOString();
