function getNextSundayDate() {
    var today = new Date();
    var dayOfWeek = today.getDay(); // 0=Sunday
    var daysToAdd = dayOfWeek === 0 ? 7 : 7 - dayOfWeek;
    var sunday = new Date(today);
    sunday.setDate(today.getDate() + daysToAdd);
    var y = sunday.getFullYear();
    var m = String(sunday.getMonth() + 1).padStart(2, '0');
    var d = String(sunday.getDate()).padStart(2, '0');
    return y + '-' + m + '-' + d;
}

