    const [mixStr, chStr] = key.split(':');
    const mix = parseInt(mixStr);
    const ch  = parseInt(chStr);
    const e   = state[key];
    const cons = channels[ch] || {};
    for (const attr of TRACKED) {
        if (e[attr] === undefined) continue;
        const c = cons[attr];
        if (!c) continue;
        if (JSON.stringify(e[attr]) !== JSON.stringify(c.consensus)) {
            variances.push({
                mix, channel: ch, attribute: attr,
                consensus: c.consensus,
                actual:    e[attr],
                severity:  SEVERITY[attr]
            });
        }
    }
}

