AND depth < ${depthLimit}
ORDER BY millis DESC
;`;

return msg;

flow.set('api_token', msg.payload);
node.status({fill:'green',shape:'dot',text:'token set'});
return null;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

const body = msg.req.body;
if (!body || !body.cmd) {
    msg.statusCode = 400;
    msg.payload = { error: 'Bad Request: cmd field required' };
    return [msg, null];
}

const hubMsg = {
    cmd:       body.cmd,
    payload:   body.payload !== undefined ? body.payload : '',
    parm:      body.parm    || {},
    source:    body.source  || 'http-api',
    flow:      'HTTP API',
    level:     'INFO',
    millis:    Date.now(),
    depth:     body.depth   || 1,
    message:   body.message || body.cmd,
    _orgmsgid: msg._msgid
};

msg.statusCode = 200;
msg.payload = { ok: true, cmd: body.cmd, millis: hubMsg.millis };
return [msg, hubMsg];

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

msg.statusCode = 200;
msg.payload = {
    input_map:     global.get('input_map')     ?? null,
    service_title: global.get('service_title') ?? null,
    filtertime:    global.get('filtertime')    ?? null,
    filterdepth:   global.get('filterdepth')   ?? null,
    filter1sec:    global.get('filter1sec')    ?? null,
    klang_variances:  global.get('klang_variances')  ?? null,
    klang_master_mix: global.get('klang_master_mix') ?? null,
    klang_test_mode:  global.get('klang_test_mode')  ?? false,
};
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

const body = msg.req.body;
if (!body || typeof body !== 'object' || Array.isArray(body)) {
    msg.statusCode = 400;
    msg.payload = { error: 'Bad Request: JSON object body required' };
    return msg;
}
const allowed = ['input_map','service_title','filtertime','filterdepth','filter1sec','test_results','klang_live_state','klang_variances','klang_master_mix','klang_test_mode'];
const set = [];
Object.keys(body).forEach(k => {
    if (allowed.includes(k)) { global.set(k, body[k]); set.push(k); }
});
msg.statusCode = 200;
msg.payload = { ok: true, set };
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

const q     = msg.req.query;
const limit = Math.min(parseInt(q.limit) || 50, 500);
const since = parseInt(q.since) || 0;
const cmd   = q.cmd ? q.cmd.replace(/'/g, "''") : null;
const cmdClause = cmd ? `AND cmd = '${cmd}'` : '';
msg.topic = `SELECT * FROM eventlog WHERE millis > ${since} ${cmdClause} ORDER BY millis DESC LIMIT ${limit};`;
return [msg, null];

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

const q      = msg.req.query;
const device = q.device || null;
const since  = Number(q.since) || 0;
const results = global.get('test_results') || [];
msg.statusCode = 200;
msg.payload = results.filter(r =>
    r.timestamp > since && (!device || r.device === device)
);
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized: missing or invalid X-Api-Token' };
    return msg;
}

global.set('test_results', []);
msg.statusCode = 200;
msg.payload = { ok: true };
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized' };
    return msg;
}

const sweepActive = global.get('klang_sweep_active') || false;
if (sweepActive) {
    const startedAt = global.get('klang_sweep_started_at') || '?';
    msg.statusCode = 409;
    msg.payload = { ok: false, error: 'Sweep already in progress', started_at: startedAt };
    return [msg, null];
}

const hubMsg = {
    cmd: '/cc/klang/connect',
    parm: {}, source: 'http-api',
    flow: 'HTTP API', level: 'INFO',
    millis: Date.now(), depth: 1,
    message: 'POST /api/klang/buildconsensus — triggering sweep'
};

msg.statusCode = 202;
msg.payload = {
    ok: true,
    message: 'Sweep started. ~17s. Poll GET /api/klang/status for completion.',
    sweep_started_at: new Date().toISOString(),
    estimated_duration_s: 17
};
return [msg, hubMsg];

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized' };
    return msg;
}

const report = global.get('klang_variances');
if (!report) {
    msg.statusCode = 404;
    msg.payload = { ok: false, error: 'No variance report available. POST /api/klang/buildconsensus first.' };
    return msg;
}
msg.statusCode = 200;
msg.payload = report;
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized' };
    return msg;
}

const masterMix = global.get('klang_master_mix');
if (!masterMix) {
    msg.statusCode = 404;
    msg.payload = { ok: false, error: 'No master mix available. POST /api/klang/buildconsensus first.' };
    return msg;
}
msg.statusCode = 200;
msg.payload = masterMix;
return msg;

const token = msg.req.headers['x-api-token'];
const validToken = flow.get('api_token') || 'vn-api-changeme';
if (!token || token !== validToken) {
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized' };
    return msg;
}

const sweepActive  = global.get('klang_sweep_active')    || false;
const startedAt    = global.get('klang_sweep_started_at') || null;
const sweepMix     = global.get('klang_sweep_mix')        || 0;
const variances    = global.get('klang_variances');
const masterMix    = global.get('klang_master_mix');

msg.statusCode = 200;
msg.payload = {
    sweep_active:      sweepActive,
    sweep_started_at:  startedAt,
    sweep_mix_current: sweepMix,
    results_available: !!variances,
    results_generated_at: variances ? variances.generated_at : null,
    total_variances:   variances ? variances.total_variances : null
};
return msg;
